/**
 * Type declarations for asset imports
 * This allows TypeScript to recognize image and font file imports
 */

declare module '*.png' {
  const value: any;
  export default value;
}

declare module '*.jpg' {
  const value: any;
  export default value;
}

declare module '*.jpeg' {
  const value: any;
  export default value;
}

declare module '*.gif' {
  const value: any;
  export default value;
}

declare module '*.svg' {
  const value: any;
  export default value;
}

declare module '*.ttf' {
  const value: any;
  export default value;
}

declare module '*.otf' {
  const value: any;
  export default value;
}

declare module '*.woff' {
  const value: any;
  export default value;
}

declare module '*.woff2' {
  const value: any;
  export default value;
}
